// // This module decodes a 2-bit input into a 4-bit output where all bits are high except for the bit corresponding to the input value.
module verified_decoder_2to4(in, out);  

    input  [1:0] in;  
    output  [3:0] out;  
    reg   [3:0]  out; 

    always @(in)
          begin
            case(in)
                2'b00: out = 4'b0001;
                2'b01: out = 4'b0010;
                2'b10: out = 4'b0100;
                2'b11: out = 4'b1000;
                default: out = 4'b0000;
            endcase
          end  

endmodule
